#[test]
fn f25_js_known_value() {
    // JS([0.9, 0.1], [0.5, 0.5])
    // M = [0.7, 0.3]
    // D_KL(P||M) = 0.9*ln(0.9/0.7) + 0.1*ln(0.1/0.3)
    // D_KL(Q||M) = 0.5*ln(0.5/0.7) + 0.5*ln(0.5/0.3)
    // JS = 0.5 * (D_KL(P||M) + D_KL(Q||M))
    let p = vec![0.9, 0.1];
    let q = vec![0.5, 0.5];
    let m = vec![0.7, 0.3];
    let kl_pm = 0.9 * (0.9f64 / 0.7).ln() + 0.1 * (0.1f64 / 0.3).ln();
    let kl_qm = 0.5 * (0.5f64 / 0.7).ln() + 0.5 * (0.5f64 / 0.3).ln();
    let expected = 0.5 * (kl_pm + kl_qm);
    assert_close("JS([0.9,0.1],[0.5,0.5])", js_divergence(&p, &q), expected, 1e-12);
}

#[test]
fn f25_js_sqrt_is_metric() {
    // √JS satisfies triangle inequality (spot check, not exhaustive)
    let p = vec![0.6, 0.3, 0.1];
    let q = vec![0.2, 0.5, 0.3];
    let r = vec![0.1, 0.1, 0.8];
    let d_pq = js_divergence(&p, &q).sqrt();
    let d_qr = js_divergence(&q, &r).sqrt();
    let d_pr = js_divergence(&p, &r).sqrt();
    assert!(d_pr <= d_pq + d_qr + 1e-10,
            "Triangle inequality: d(P,R)={} > d(P,Q)+d(Q,R)={}", d_pr, d_pq + d_qr);
}

