    // Marginals: p(X=0)=0.25, p(X=1)=0.75; p(Y=0)=0.6, p(Y=1)=0.4
    // Joint = outer product
    let table = vec![
        0.15, 0.10,  // [0.25*0.6, 0.25*0.4]
        0.45, 0.30,  // [0.75*0.6, 0.75*0.4]
    ];
