#[test]
fn f25_vi_is_metric() {
    // VI is a true metric: triangle inequality check
    // We build 3 contingency tables and check VI(A,C) ≤ VI(A,B) + VI(B,C)
    // Use label-based construction for cleaner math
    let lab_a = vec![0, 0, 0, 1, 1, 1];
    let lab_b = vec![0, 0, 1, 1, 1, 1];
    let lab_c = vec![0, 1, 1, 1, 0, 0];

    fn vi_from_labels(a: &[i32], b: &[i32]) -> f64 {
        let na = a.iter().copied().max().unwrap_or(0) as usize + 1;
        let nb = b.iter().copied().max().unwrap_or(0) as usize + 1;
        let mut table = vec![0.0f64; na * nb];
        for (&ai, &bi) in a.iter().zip(b) {
            table[ai as usize * nb + bi as usize] += 1.0;
        }
        variation_of_information(&table, na, nb)
    }
    let vi_ab = vi_from_labels(&lab_a, &lab_b);
    let vi_bc = vi_from_labels(&lab_b, &lab_c);
    let vi_ac = vi_from_labels(&lab_a, &lab_c);
    assert!(vi_ac <= vi_ab + vi_bc + 1e-10,
            "VI triangle: VI(A,C)={} > VI(A,B)+VI(B,C)={}", vi_ac, vi_ab + vi_bc);
}

// ---------------------------------------------------------------------------
// F25: Conditional entropy — Gold standard: H(Y|X) = H(X,Y) - H(X)
// ---------------------------------------------------------------------------

#[test]
fn f25_conditional_entropy_independent() {
    // When X, Y independent: H(Y|X) = H(Y)
    let table = vec![0.15, 0.10, 0.45, 0.30]; // independent (see MI test)
    let hy = shannon_entropy(&probabilities(&[0.6, 0.4]));
    assert_close("H(Y|X)_indep", conditional_entropy(&table, 2, 2), hy, 1e-10);
}

#[test]
fn f25_conditional_entropy_deterministic() {
    // Y = X → H(Y|X) = 0 (knowing X fully determines Y)
    let table = vec![5.0, 0.0, 0.0, 5.0];
    assert_close("H(Y|X)_determ", conditional_entropy(&table, 2, 2), 0.0, 1e-10);
}

#[test]
fn f25_mi_chain_rule() {
    // MI(X;Y) = H(Y) - H(Y|X)
    let table = vec![3.0, 1.0, 2.0, 4.0];
    let mi = mutual_information(&table, 2, 2);
    let col_sums = [5.0, 5.0]; // 3+2, 1+4
    let hy = shannon_entropy(&probabilities(&col_sums));
    let hy_given_x = conditional_entropy(&table, 2, 2);
    assert_close("MI=H(Y)-H(Y|X)", mi, hy - hy_given_x, 1e-10);
}

// ---------------------------------------------------------------------------
// F25: AMI — Gold standard: sklearn.metrics.adjusted_mutual_info_score
// ---------------------------------------------------------------------------

#[test]
fn f25_ami_perfect() {
    // Perfect clustering → AMI = 1.0
    let true_l = vec![0, 0, 1, 1, 2, 2];
    let pred_l = vec![0, 0, 1, 1, 2, 2];
    assert_close("AMI_perfect", adjusted_mutual_info_score(&true_l, &pred_l), 1.0, 1e-10);
}

#[test]
fn f25_ami_random_near_zero() {
    // Orthogonal labeling → AMI ≈ 0 (corrected for chance)
    let true_l = vec![0, 0, 0, 1, 1, 1, 2, 2, 2];
    let pred_l = vec![0, 1, 2, 0, 1, 2, 0, 1, 2];
    let ami = adjusted_mutual_info_score(&true_l, &pred_l);
    // For n=9 orthogonal labeling, AMI is negative (corrected below chance).
    // sklearn gives AMI ≈ -0.44 for this exact case. Key property: AMI ≤ 0 for
    // independent labelings (below chance after correction).
    assert!(ami <= 0.01,
            "Random labeling AMI should be ≤ 0, got {}", ami);
}

// ---------------------------------------------------------------------------
// F25: Sharing chain — histogram → entropy → MI → NMI
// ---------------------------------------------------------------------------

#[test]
fn f25_sharing_chain_counts_to_nmi() {
    // Verify the full chain: counts → probabilities → entropy → MI → NMI
    // All from the same contingency table
    let table = vec![
        5.0, 0.0, 0.0,
        0.0, 3.0, 0.0,
        0.0, 0.0, 7.0,
    ];
    let n = 15.0f64; // 5+3+7

    // Step 1: Marginal entropies from the same table
    let row_sums = [5.0, 3.0, 7.0];
    let col_sums = [5.0, 3.0, 7.0]; // block diagonal → same
    let hx = shannon_entropy(&probabilities(&row_sums));
    let hy = shannon_entropy(&probabilities(&col_sums));

    // Step 2: MI from the table
    let mi = mutual_information(&table, 3, 3);

    // Step 3: For perfect block diagonal, MI = H(X) = H(Y)
    assert_close("MI=H(X)", mi, hx, 1e-10);
    assert_close("MI=H(Y)", mi, hy, 1e-10);

    // Step 4: NMI = 1.0 for perfect clustering
    let nmi = normalized_mutual_information(&table, 3, 3, "arithmetic");
    assert_close("NMI_chain", nmi, 1.0, 1e-10);

    // Step 5: VI = 0 for perfect clustering
    let vi = variation_of_information(&table, 3, 3);
    assert_close("VI_chain", vi, 0.0, 1e-10);
}

// ---------------------------------------------------------------------------
// F25: Information-theoretic identities (mathematical self-consistency)
// ---------------------------------------------------------------------------

#[test]
fn f25_identities_entropy_divergence() {
    // H(P,Q) = H(P) + KL(P||Q)  — already tested, but verify on different data
    // KL(P||Q) ≥ 0  — Gibbs' inequality
    // JS(P,Q) = H(M) - 0.5*H(P) - 0.5*H(Q)  where M=(P+Q)/2
    let p = vec![0.4, 0.35, 0.25];
    let q = vec![0.1, 0.6, 0.3];
    let m: Vec<f64> = p.iter().zip(&q).map(|(&a, &b)| (a + b) / 2.0).collect();

    // JS via entropies
    let js_via_entropies = shannon_entropy(&m) - 0.5 * shannon_entropy(&p) - 0.5 * shannon_entropy(&q);
    let js_direct = js_divergence(&p, &q);
    assert_close("JS_entropy_form", js_direct, js_via_entropies, 1e-12);
}

#[test]
fn f25_vi_decomposition() {
    // VI(X,Y) = H(X) + H(Y) - 2*MI(X;Y)
    let table = vec![3.0, 1.0, 0.0, 1.0, 4.0, 1.0, 0.0, 1.0, 3.0];
    let row_sums = [4.0, 6.0, 4.0];
    let col_sums = [4.0, 6.0, 4.0];
    let hx = shannon_entropy(&probabilities(&row_sums));
    let hy = shannon_entropy(&probabilities(&col_sums));
    let mi = mutual_information(&table, 3, 3);
    let vi = variation_of_information(&table, 3, 3);
    let expected_vi = hx + hy - 2.0 * mi;
    assert_close("VI=H(X)+H(Y)-2MI", vi, expected_vi.max(0.0), 1e-10);
}

