#[test]
fn f09_sharing_chain_from_descriptive() {
    // F09 uses sorted_nan_free and median from F06 (descriptive.rs)
    // Verify the shared functions produce consistent results
    use tambear::descriptive::{sorted_nan_free, median, mad};

    let data_with_nan = vec![3.0, f64::NAN, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0];
    let clean = sorted_nan_free(&data_with_nan);
    let mad_val = mad(&clean); // mad expects sorted NaN-free data

    // Huber M-estimate uses the same sorted_nan_free + median internally
    let r = huber_m_estimate(&data_with_nan, 1.345, 100, 1e-8);
    // The scale should be MAD * 1.4826
    assert_close("huber_scale_matches_descriptive_mad",
                 r.scale, mad_val * 1.4826, 1e-10);
}

