// ===========================================================================
// F26: COMPLEXITY & CHAOS — Gold standard: analytical properties, nolds library
//
// Oracle chain:
//   SampEn/ApEn: analytical bounds + known system properties
//   Permutation entropy: Bandt & Pompe (2002) bounds: 0 ≤ PE ≤ log(m!)
//   Hurst: H=0.5 for random walk (well-established)
//   DFA: α=0.5 for white noise, α≈1.5 for integrated noise
//   Higuchi FD: D=2 for white noise, D≈1.5 for Brownian motion
//   LZ: ~0 for periodic, ~1 for random
//
// These algorithms have stochastic elements, so tests use wide tolerances
// and focus on ordering/sign/bound properties rather than exact values.
// ===========================================================================

use tambear::complexity::{
    sample_entropy, approx_entropy, permutation_entropy, normalized_permutation_entropy,
    hurst_rs, dfa, higuchi_fd, lempel_ziv_complexity,
    correlation_dimension, largest_lyapunov,
};

// ---------------------------------------------------------------------------
// F26: Sample Entropy — Gold standard: Richman & Moorman (2000)
// ---------------------------------------------------------------------------

#[test]
fn f26_sample_entropy_constant_is_low() {
    // Constant signal: all templates match → SampEn ≈ 0 or NaN (no divergence)
    let data = vec![5.0; 200];
    let se = sample_entropy(&data, 2, 0.2);
    // Either very low or undefined (implementation-dependent for degenerate case)
    assert!(se.abs() < 0.1 || se.is_nan() || se.is_infinite(),
            "SampEn(constant)={} should be ≈0 or undefined", se);
}

#[test]
fn f26_sample_entropy_periodic_is_low() {
    // Periodic sin wave: predictable → low SampEn
    let data: Vec<f64> = (0..500).map(|i| (i as f64 * 0.1).sin()).collect();
    let std: f64 = (data.iter().map(|x| x.powi(2)).sum::<f64>() / data.len() as f64).sqrt();
    let se = sample_entropy(&data, 2, 0.2 * std);
    assert!(se < 1.0, "SampEn(periodic)={} should be low", se);
}

#[test]
fn f26_sample_entropy_random_gt_periodic() {
    // Random data should have higher SampEn than periodic
    let periodic: Vec<f64> = (0..300).map(|i| (i as f64 * 0.2).sin()).collect();
    // Pseudo-random using simple LCG-like construction
    let random: Vec<f64> = (0..300).map(|i| {
        let x = (i as f64 * 137.0 + 0.7).sin() * 10000.0;
        x - x.floor()
    }).collect();

    let std_p: f64 = (periodic.iter().map(|x| x.powi(2)).sum::<f64>() / 300.0).sqrt();
    let std_r: f64 = (random.iter().map(|x| x.powi(2)).sum::<f64>() / 300.0).sqrt();

    let se_periodic = sample_entropy(&periodic, 2, 0.2 * std_p);
    let se_random = sample_entropy(&random, 2, 0.2 * std_r);

    // Random should be more complex than periodic
    if !se_periodic.is_infinite() && !se_random.is_infinite() {
        assert!(se_random > se_periodic,
                "SampEn: random={} should > periodic={}", se_random, se_periodic);
    }
}

#[test]
fn f26_sample_entropy_non_negative() {
    // SampEn ≥ 0 (it's -ln(A/B) where 0 < A ≤ B, so A/B ≤ 1, ln ≤ 0, negation ≥ 0)
    let data: Vec<f64> = (0..200).map(|i| (i as f64 * 0.3).sin() * 2.0).collect();
    let std: f64 = (data.iter().map(|x| x.powi(2)).sum::<f64>() / 200.0).sqrt();
    let se = sample_entropy(&data, 2, 0.2 * std);
    if !se.is_nan() && !se.is_infinite() {
        assert!(se >= -1e-10, "SampEn must be non-negative: {}", se);
    }
}

