// F26: Approximate Entropy — Gold standard: Pincus (1991)
// ---------------------------------------------------------------------------

#[test]
fn f26_approx_entropy_non_negative() {
    // ApEn ≥ 0 for all signals
    let data: Vec<f64> = (0..200).map(|i| (i as f64 * 0.1).sin()).collect();
    let apen = approx_entropy(&data, 2, 0.2);
    assert!(apen >= -1e-10, "ApEn must be non-negative: {}", apen);
}

#[test]
fn f26_approx_entropy_periodic_is_low() {
    let data: Vec<f64> = (0..500).map(|i| (i as f64 * 0.1).sin()).collect();
    let apen = approx_entropy(&data, 2, 0.2);
    assert!(apen < 0.5, "ApEn(periodic)={} should be low", apen);
}

// ---------------------------------------------------------------------------
// F26: Permutation Entropy — Gold standard: Bandt & Pompe (2002)
// ---------------------------------------------------------------------------

#[test]
fn f26_permutation_entropy_monotonic_is_zero() {
    // Strictly monotonic data → single permutation pattern → PE = 0
    let data: Vec<f64> = (0..100).map(|i| i as f64).collect();
    let pe = permutation_entropy(&data, 3, 1);
    assert_close("PE(monotonic)", pe, 0.0, 1e-10);
}

#[test]
fn f26_permutation_entropy_bounded() {
    // PE ∈ [0, log(m!)]
    let data: Vec<f64> = (0..500).map(|i| {
        (i as f64 * 137.0 + 0.7).sin() * 10000.0
    }).collect();
    let m = 4;
    let pe = permutation_entropy(&data, m, 1);
    let max_pe = (factorial_f64(m)).ln();
    assert!(pe >= -1e-10, "PE must be ≥ 0: {}", pe);
    assert!(pe <= max_pe + 1e-10, "PE must be ≤ log({}!)={}: got {}", m, max_pe, pe);
}

#[test]
fn f26_normalized_pe_range() {
    // Normalized PE ∈ [0, 1]
    let data: Vec<f64> = (0..500).map(|i| {
        (i as f64 * 73.0 + 0.3).sin() * 1000.0
    }).collect();
    let npe = normalized_permutation_entropy(&data, 4, 1);
    if !npe.is_nan() {
        assert!(npe >= -1e-10 && npe <= 1.0 + 1e-10, "NPE out of [0,1]: {}", npe);
    }
}

#[test]
fn f26_normalized_pe_monotonic_is_zero() {
    let data: Vec<f64> = (0..100).map(|i| i as f64).collect();
    let npe = normalized_permutation_entropy(&data, 3, 1);
    assert_close("NPE(monotonic)", npe, 0.0, 1e-10);
}

// ---------------------------------------------------------------------------
// F26: Hurst exponent — Gold standard: H=0.5 for random walk
// ---------------------------------------------------------------------------

#[test]
fn f26_hurst_range() {
    // Hurst exponent should be in (0, 1) for real data
    // Use a deterministic pseudo-random sequence
    let data: Vec<f64> = (0..1000).map(|i| {
        (i as f64 * 137.0 + 0.7).sin() * 10000.0
    }).collect();
    let h = hurst_rs(&data);
    if !h.is_nan() {
        assert!(h > 0.0 && h < 1.5, "Hurst out of range: {}", h);
    }
}

#[test]
fn f26_hurst_trending_gt_random() {
    // Trending (cumulative sum) data should have higher H than oscillating data
    let cumsum: Vec<f64> = {
        let mut s = vec![0.0; 500];
        for i in 1..500 {
            s[i] = s[i-1] + (i as f64 * 0.01).sin();
        }
        s
    };
    let oscillating: Vec<f64> = (0..500).map(|i| if i % 2 == 0 { 1.0 } else { -1.0 }).collect();
    let h_trend = hurst_rs(&cumsum);
    let h_osc = hurst_rs(&oscillating);
    // Trending data: H > 0.5, anti-persistent: H < 0.5
    if !h_trend.is_nan() && !h_osc.is_nan() {
        assert!(h_trend > h_osc,
                "H(trending)={} should > H(oscillating)={}", h_trend, h_osc);
    }
}

