#[test]
fn f26_higuchi_monotonic_is_one() {
    // Linear (smooth) data: FD ≈ 1.0
    let data: Vec<f64> = (0..200).map(|i| i as f64 * 0.5).collect();
    let fd = higuchi_fd(&data, 10);
    if !fd.is_nan() {
        assert!(fd < 1.3, "Higuchi FD(linear)={} should be near 1.0", fd);
    }
}

#[test]
fn f26_higuchi_complex_gt_smooth() {
    // More complex signal should have higher FD
    let smooth: Vec<f64> = (0..500).map(|i| (i as f64 * 0.01).sin()).collect();
    let complex: Vec<f64> = (0..500).map(|i| {
        (i as f64 * 0.1).sin() + (i as f64 * 0.37).cos() * 0.5
            + (i as f64 * 1.7).sin() * 0.2
    }).collect();
    let fd_smooth = higuchi_fd(&smooth, 10);
    let fd_complex = higuchi_fd(&complex, 10);
    if !fd_smooth.is_nan() && !fd_complex.is_nan() {
        assert!(fd_complex > fd_smooth,
                "Higuchi: complex={} should > smooth={}", fd_complex, fd_smooth);
    }
}

