#[test]
fn f26_oracle_sampen_ordering() {
    // nolds: SampEn(periodic sin) = 0.240, SampEn(random) = 2.113
    // Key property: random >> periodic
    let periodic: Vec<f64> = (0..500).map(|i| (i as f64 * 0.1).sin()).collect();
    let std_p: f64 = (periodic.iter().map(|x| x.powi(2)).sum::<f64>() / 500.0).sqrt();
    let se_p = sample_entropy(&periodic, 2, 0.2 * std_p);
    // nolds gives 0.240 — tambear should be in same ballpark (< 1.0)
    if !se_p.is_nan() && !se_p.is_infinite() {
        assert!(se_p < 1.0, "nolds: SampEn(periodic)=0.24, tambear={}", se_p);
    }
}

#[test]
fn f26_oracle_dfa_white_noise() {
    // nolds.dfa(white_noise) = 0.538 (expected ~0.5)
    // Use deterministic pseudo-random for reproducibility
    let data: Vec<f64> = (0..1000).map(|i| {
        (i as f64 * 137.0 + 0.7).sin() * 10000.0 % 1.0
    }).collect();
    let alpha = dfa(&data, 4, 64);
    if !alpha.is_nan() {
        // DFA alpha for white noise should be in [0.2, 1.0]
        assert!(alpha > 0.2 && alpha < 1.0,
            "nolds: DFA(white)=0.538, tambear={}", alpha);
    }
}

#[test]
fn f26_oracle_pe_max_bounds() {
    // Analytical: max PE(m=3) = ln(3!) = ln(6) = 1.7917594692280550
    // Analytical: max PE(m=4) = ln(4!) = ln(24) = 3.1780538303479458
    let max_m3 = 1.7917594692280550;
    let max_m4 = 3.1780538303479458;

    // Verify PE of highly irregular data approaches max
    let data: Vec<f64> = (0..1000).map(|i| {
        (i as f64 * 137.0 + 0.7).sin() * 10000.0
    }).collect();

    let pe3 = permutation_entropy(&data, 3, 1);
    let pe4 = permutation_entropy(&data, 4, 1);

    assert!(pe3 <= max_m3 + 1e-10, "PE(m=3)={} exceeds max={}", pe3, max_m3);
    assert!(pe4 <= max_m4 + 1e-10, "PE(m=4)={} exceeds max={}", pe4, max_m4);
    // Pseudo-random-ish data should have substantial PE (> 50% of max)
    assert!(pe3 > 0.5 * max_m3, "PE(m=3)={} should be substantial vs max={}", pe3, max_m3);
    assert!(pe4 > 0.5 * max_m4, "PE(m=4)={} should be substantial vs max={}", pe4, max_m4);
}

#[test]
fn f26_oracle_corr_dim_sine_low() {
    // nolds.corr_dim(sine, emb_dim=3) = 1.061
    // Sine wave is a 1D attractor; corr_dim should be low (< 2)
    let data: Vec<f64> = (0..500).map(|i| (i as f64 * 0.1).sin()).collect();
    let cd = correlation_dimension(&data, 3, 1);
    if !cd.is_nan() {
        assert!(cd < 3.0, "nolds: corr_dim(sine)=1.06, tambear={}", cd);
        assert!(cd > 0.0, "corr_dim must be positive");
    }
}

// ===========================================================================
// F31: INTERPOLATION & APPROXIMATION — Gold standard: exact interpolation
//
// Oracle: interpolation through known points is exact (f(xi) = yi).
// Polynomials of degree <= n interpolated by n+1 points are exact everywhere.
// Known function approximations have bounded error.
// ===========================================================================

use tambear::interpolation::{
    lagrange, newton_divided_diff, newton_eval, neville, lerp, nearest,
    natural_cubic_spline, clamped_cubic_spline, monotone_hermite, akima, pchip,
    chebyshev_nodes, chebyshev_approximate, chebyshev_eval,
    polyfit, barycentric_rational, pade,
};

// ---------------------------------------------------------------------------
// F31: Lagrange interpolation — Gold standard: exact on data points
// ---------------------------------------------------------------------------

#[test]
fn f31_lagrange_exact_at_nodes() {
    // Interpolation must pass through all data points
    let xs = vec![0.0, 1.0, 2.0, 3.0];
    let ys = vec![1.0, 3.0, 2.0, 5.0];
    for i in 0..xs.len() {
        assert_close(&format!("lagrange(x{})", i), lagrange(&xs, &ys, xs[i]), ys[i], 1e-12);
    }
}

#[test]
fn f31_lagrange_exact_for_polynomial() {
    // 3 points define a unique degree-2 polynomial. y = x² + 1 at x={0,1,2}
    // Lagrange should recover the polynomial exactly at any point
    let xs = vec![0.0, 1.0, 2.0];
    let ys = vec![1.0, 2.0, 5.0]; // 0²+1, 1²+1, 2²+1
    // Check at x=0.5: 0.25+1 = 1.25
    assert_close("lagrange_poly(0.5)", lagrange(&xs, &ys, 0.5), 1.25, 1e-12);
    // At x=1.5: 2.25+1 = 3.25
    assert_close("lagrange_poly(1.5)", lagrange(&xs, &ys, 1.5), 3.25, 1e-12);
}

// ---------------------------------------------------------------------------
// F31: Newton interpolation — Gold standard: same as Lagrange
// ---------------------------------------------------------------------------

#[test]
fn f31_newton_matches_lagrange() {
    let xs = vec![0.0, 1.0, 2.0, 3.0, 4.0];
    let ys = vec![1.0, 3.0, 2.0, 5.0, 4.0];
    let coeffs = newton_divided_diff(&xs, &ys);
    // Newton and Lagrange should agree at arbitrary points
    for &x in &[0.5, 1.5, 2.5, 3.5] {
        let l = lagrange(&xs, &ys, x);
        let n = newton_eval(&xs, &coeffs, x);
        assert_close(&format!("newton_vs_lagrange({})", x), n, l, 1e-10);
    }
}

// ---------------------------------------------------------------------------
// F31: Neville — Gold standard: same polynomial, with error estimate
// ---------------------------------------------------------------------------

#[test]
fn f31_neville_matches_lagrange() {
    let xs = vec![0.0, 1.0, 2.0, 3.0];
    let ys = vec![1.0, 0.0, 1.0, 0.0];
    for &x in &[0.5, 1.5, 2.5] {
        let (val, _err) = neville(&xs, &ys, x);
        let l = lagrange(&xs, &ys, x);
        assert_close(&format!("neville({})", x), val, l, 1e-10);
    }
}

// ---------------------------------------------------------------------------
// F31: Linear interpolation — Gold standard: exact linear
// ---------------------------------------------------------------------------

#[test]
fn f31_lerp_exact() {
    let xs = vec![0.0, 1.0, 2.0, 3.0];
    let ys = vec![0.0, 2.0, 4.0, 6.0]; // y = 2x
    // Midpoint: lerp(0.5) = 1.0
    assert_close("lerp(0.5)", lerp(&xs, &ys, 0.5), 1.0, 1e-12);
    assert_close("lerp(1.5)", lerp(&xs, &ys, 1.5), 3.0, 1e-12);
    assert_close("lerp(2.5)", lerp(&xs, &ys, 2.5), 5.0, 1e-12);
}

