#[test]
fn f31_natural_spline_linear_data() {
    // For linear data y=2x+1, cubic spline should reproduce exactly
    let xs = vec![0.0, 1.0, 2.0, 3.0, 4.0];
    let ys: Vec<f64> = xs.iter().map(|&x| 2.0 * x + 1.0).collect();
    let spline = natural_cubic_spline(&xs, &ys);
    // Check at midpoints
    assert_close("spline_lin(0.5)", spline.eval(0.5), 2.0, 1e-8);
    assert_close("spline_lin(2.5)", spline.eval(2.5), 6.0, 1e-8);
}

#[test]
fn f31_monotone_hermite_preserves_monotonicity() {
    // Monotone data → spline must be monotone between nodes
    let xs = vec![0.0, 1.0, 2.0, 3.0, 4.0];
    let ys = vec![1.0, 2.0, 3.0, 5.0, 8.0];
    let spline = monotone_hermite(&xs, &ys);
    // Check monotonicity at fine grid
    let mut prev = spline.eval(0.0);
    for i in 1..40 {
        let x = i as f64 * 0.1;
        let y = spline.eval(x);
        assert!(y >= prev - 1e-10, "Monotone hermite violated at x={}: {} < {}", x, y, prev);
        prev = y;
    }
}

// ---------------------------------------------------------------------------
// F31: Chebyshev approximation — Gold standard: exponential convergence
// ---------------------------------------------------------------------------

#[test]
fn f31_chebyshev_nodes_endpoints() {
    // n Chebyshev nodes on [a,b], all within [a,b]
    let nodes = chebyshev_nodes(10, -1.0, 1.0);
    assert_eq!(nodes.len(), 10);
    for &x in &nodes {
        assert!(x >= -1.0 - 1e-10 && x <= 1.0 + 1e-10, "Chebyshev node out of range: {}", x);
    }
}

#[test]
fn f31_chebyshev_approximates_exp() {
    // Chebyshev approximation of exp(x) on [-1, 1]
    let coeffs = chebyshev_approximate(&|x: f64| x.exp(), 15, -1.0, 1.0);
    // Should be very accurate with 15 terms
    for &x in &[-0.9, -0.5, 0.0, 0.5, 0.9] {
        let approx = chebyshev_eval(&coeffs, x, -1.0, 1.0);
        assert_close(&format!("cheb_exp({})", x), approx, x.exp(), 1e-10);
    }
}

