//   Differentiation: exact derivatives
//   ODE: exact solutions (exponential decay, harmonic oscillator)
//
// These have EXACT gold standards — no external library needed.
// ===========================================================================

use tambear::numerical::{
    bisection, newton, secant, brent, fixed_point,
    derivative_central, derivative2_central, derivative_richardson,
    simpson, gauss_legendre_5, adaptive_simpson, trapezoid,
    euler, rk4, rk45, rk4_system,
};

// ---------------------------------------------------------------------------
// F32: Root finding — Gold standard: exact polynomial roots
// ---------------------------------------------------------------------------

#[test]
fn f32_bisection_sqrt2() {
    // x² - 2 = 0 on [1, 2] → root = √2
    let r = bisection(|x| x * x - 2.0, 1.0, 2.0, 1e-12, 100);
    assert!(r.converged, "Bisection should converge");
    assert_close("bisection_sqrt2", r.root, std::f64::consts::SQRT_2, 1e-10);
}

#[test]
fn f32_bisection_cubic() {
    // x³ - x - 2 = 0 on [1, 2] → root ≈ 1.5214
    let r = bisection(|x| x * x * x - x - 2.0, 1.0, 2.0, 1e-12, 100);
    assert!(r.converged);
    // Verify: f(root) ≈ 0
    let f_val = r.root.powi(3) - r.root - 2.0;
    assert!(f_val.abs() < 1e-10, "f(root)={}", f_val);
}

#[test]
fn f32_newton_sqrt2() {
    // x² - 2 = 0, f'(x) = 2x, x₀ = 1.5
    let r = newton(|x| x * x - 2.0, |x| 2.0 * x, 1.5, 1e-12, 50);
    assert!(r.converged, "Newton should converge");
    assert_close("newton_sqrt2", r.root, std::f64::consts::SQRT_2, 1e-12);
    // Newton is quadratic: should converge in few iterations
    assert!(r.iterations < 10, "Newton too slow: {} iters", r.iterations);
}

#[test]
fn f32_newton_cos_zero() {
    // cos(x) = 0 near x=1.5 → root = π/2
    let r = newton(|x| x.cos(), |x| -x.sin(), 1.5, 1e-12, 50);
    assert!(r.converged);
    assert_close("newton_pi_half", r.root, std::f64::consts::FRAC_PI_2, 1e-10);
}

#[test]
fn f32_secant_sqrt2() {
    let r = secant(|x| x * x - 2.0, 1.0, 2.0, 1e-12, 50);
    assert!(r.converged, "Secant should converge");
    assert_close("secant_sqrt2", r.root, std::f64::consts::SQRT_2, 1e-10);
}

#[test]
fn f32_brent_sqrt2() {
    let r = brent(|x| x * x - 2.0, 1.0, 2.0, 1e-12, 100);
    assert!(r.converged, "Brent should converge");
    assert_close("brent_sqrt2", r.root, std::f64::consts::SQRT_2, 1e-10);
}

#[test]
fn f32_brent_exp_minus_2() {
    // exp(x) = 2 → root = ln(2)
    let r = brent(|x| x.exp() - 2.0, 0.0, 1.0, 1e-12, 100);
    assert!(r.converged);
    assert_close("brent_ln2", r.root, 2.0f64.ln(), 1e-10);
}

#[test]
fn f32_fixed_point_cos() {
    // Fixed point of cos: x = cos(x) → x ≈ 0.7390851332...
    // (Dottie number)
    let r = fixed_point(|x| x.cos(), 0.5, 1e-10, 100);
    assert!(r.converged, "Fixed point should converge");
    // Verify: cos(root) = root
    assert_close("fp_cos_fixpoint", r.root.cos(), r.root, 1e-8);
}

#[test]
fn f32_all_root_finders_agree() {
    // All methods should find the same root for x² - 3 = 0 → √3
    let f = |x: f64| x * x - 3.0;
    let sqrt3 = 3.0f64.sqrt();

    let r_bis = bisection(f, 1.0, 2.0, 1e-12, 100);
    let r_new = newton(f, |x| 2.0 * x, 1.5, 1e-12, 50);
    let r_sec = secant(f, 1.0, 2.0, 1e-12, 50);
    let r_bre = brent(f, 1.0, 2.0, 1e-12, 100);

    assert_close("bisection_sqrt3", r_bis.root, sqrt3, 1e-10);
    assert_close("newton_sqrt3", r_new.root, sqrt3, 1e-10);
    assert_close("secant_sqrt3", r_sec.root, sqrt3, 1e-10);
    assert_close("brent_sqrt3", r_bre.root, sqrt3, 1e-10);
}

