#[test]
fn f32_adaptive_simpson_exp() {
    // ∫₀¹ exp(x) dx = e - 1 ≈ 1.71828...
    let result = adaptive_simpson(|x| x.exp(), 0.0, 1.0, 1e-10, 20);
    assert_close("adaptive_∫exp[0,1]", result, std::f64::consts::E - 1.0, 1e-8);
}

#[test]
fn f32_trapezoid_sin() {
    // ∫₀^π sin(x) dx = 2.0 (trapezoid with enough points)
    let result = trapezoid(|x| x.sin(), 0.0, std::f64::consts::PI, 1000);
    assert_close("trap_∫sin[0,π]", result, 2.0, 1e-4);
}

#[test]
fn f32_integration_methods_agree() {
    // All methods on same integral: ∫₀¹ exp(-x²) dx ≈ 0.7468241328...
    // (erf(1)*√π/2)
    let exact = 0.5 * std::f64::consts::PI.sqrt() * tambear::erf(1.0);
    let s = simpson(|x| (-x * x).exp(), 0.0, 1.0, 200);
    let gl = gauss_legendre_5(|x| (-x * x).exp(), 0.0, 1.0);
    let ad = adaptive_simpson(|x| (-x * x).exp(), 0.0, 1.0, 1e-10, 20);
    let tr = trapezoid(|x| (-x * x).exp(), 0.0, 1.0, 1000);

    assert_close("simpson_erf", s, exact, 1e-6);
    assert_close("GL5_erf", gl, exact, 1e-4);
    assert_close("adaptive_erf", ad, exact, 1e-6);
    assert_close("trapezoid_erf", tr, exact, 1e-4);
}

// ---------------------------------------------------------------------------
// F32: ODE solvers — Gold standard: exact solutions
// ---------------------------------------------------------------------------

#[test]
fn f32_euler_exponential_decay() {
    // dy/dt = -y, y(0) = 1 → y(t) = exp(-t)
    let sol = euler(|_t, y| -y, 1.0, 0.0, 1.0, 1000);
    let y_final = sol.y[sol.y.len() - 1];
    // Euler is first-order: h=0.001, error ~ h = 1e-3
    assert_close("euler_exp_decay", y_final, (-1.0f64).exp(), 5e-3);
}

#[test]
fn f32_rk4_exponential_decay() {
    // Same problem, RK4 should be much more accurate
    let sol = rk4(|_t, y| -y, 1.0, 0.0, 1.0, 100);
    let y_final = sol.y[sol.y.len() - 1];
    // RK4 is fourth-order: h=0.01, error ~ h⁴ = 1e-8
    assert_close("rk4_exp_decay", y_final, (-1.0f64).exp(), 1e-6);
}

#[test]
fn f32_rk4_more_accurate_than_euler() {
    // With same number of steps, RK4 should be more accurate
    let n = 50;
    let exact = (-1.0f64).exp();
    let sol_e = euler(|_t, y| -y, 1.0, 0.0, 1.0, n);
    let sol_r = rk4(|_t, y| -y, 1.0, 0.0, 1.0, n);
    let err_e = (sol_e.y[sol_e.y.len() - 1] - exact).abs();
    let err_r = (sol_r.y[sol_r.y.len() - 1] - exact).abs();
    assert!(err_r < err_e, "RK4 error={} should < Euler error={}", err_r, err_e);
}

#[test]
fn f32_rk45_adaptive_precision() {
    // RK45 with adaptive stepping should achieve tight tolerance
    let sol = rk45(|_t, y| -y, 1.0, 0.0, 1.0, 1e-8, 0.01);
    let y_final = sol.y[sol.y.len() - 1];
    assert_close("rk45_exp_decay", y_final, (-1.0f64).exp(), 1e-6);
}

#[test]
fn f32_rk4_system_harmonic() {
    // Harmonic oscillator: y'' + y = 0
    // State: [y, y'] → [y', -y]
    // y(0) = 1, y'(0) = 0 → y(t) = cos(t)
    let (t_vec, y_vec) = rk4_system(
        |_t, state| vec![ state[1], -state[0] ],
        &[1.0, 0.0], // y(0)=1, y'(0)=0
        0.0,
        std::f64::consts::PI, // integrate to π
        200,
    );
    // y(π) = cos(π) = -1
    let y_final = y_vec[y_vec.len() - 1][0];
    assert_close("rk4_harmonic_y(π)", y_final, -1.0, 1e-4);
    // y'(π) = -sin(π) ≈ 0
    let yp_final = y_vec[y_vec.len() - 1][1];
    assert!(yp_final.abs() < 0.01, "y'(π) should be ≈0: {}", yp_final);
}

