#[test]
fn f32_integrate_recovers_erf() {
    // erf(x) = (2/√π) ∫₀ˣ exp(-t²) dt
    // Verify our integration of exp(-t²) matches our erf implementation
    let x = 1.0;
    let integral = adaptive_simpson(|t| (-t * t).exp(), 0.0, x, 1e-10, 20);
    let erf_from_integral = 2.0 / std::f64::consts::PI.sqrt() * integral;
    let erf_direct = tambear::erf(x);
    assert_close("∫ vs erf(1)", erf_from_integral, erf_direct, 1e-6);
}

