// ── LU and solve ──

#[test]
fn f02_solve_2x2_known() {
    // [2,1; 1,3] x = [5,7] → x = [8/5, 9/5] = [1.6, 1.8]
    // numpy.linalg.solve
    let a = Mat::from_rows(&[&[2.0, 1.0], &[1.0, 3.0]]);
    let b = vec![5.0, 7.0];
    let x = solve(&a, &b).unwrap();
    assert_close("x[0]", x[0], 1.6, 1e-10);
    assert_close("x[1]", x[1], 9.0 / 5.0, 1e-10);
}

#[test]
fn f02_solve_3x3_residual() {
    // Solve Ax=b then verify ||Ax - b|| ≈ 0
    let a = Mat::from_rows(&[
        &[3.0, 1.0, -1.0],
        &[1.0, 4.0, 2.0],
        &[-1.0, 2.0, 5.0],
    ]);
    let b = vec![4.0, 15.0, 12.0];
    let x = solve(&a, &b).unwrap();
    let ax = mat_vec(&a, &x);
    for i in 0..3 {
        assert_close(&format!("residual[{}]", i), ax[i], b[i], 1e-10);
    }
}

#[test]
fn f02_inv_times_a_is_identity() {
    // A * A^{-1} = I (numpy.linalg.inv)
    let a = Mat::from_rows(&[
        &[1.0, 2.0, 3.0],
        &[0.0, 1.0, 4.0],
        &[5.0, 6.0, 0.0],
    ]);
    let a_inv = inv(&a).unwrap();
    let product = mat_mul(&a, &a_inv);
    mat_close("A*A^-1", &product, &Mat::eye(3), 1e-10);
}

#[test]
fn f02_inv_2x2_analytical() {
    // inv([[a,b],[c,d]]) = (1/det) * [[d,-b],[-c,a]]
    // inv([[1,2],[3,4]]) = (-1/2) * [[4,-2],[-3,1]] = [[-2,1],[1.5,-0.5]]
    let a = Mat::from_rows(&[&[1.0, 2.0], &[3.0, 4.0]]);
    let a_inv = inv(&a).unwrap();
    assert_close("inv[0,0]", a_inv.get(0, 0), -2.0, 1e-10);
    assert_close("inv[0,1]", a_inv.get(0, 1), 1.0, 1e-10);
    assert_close("inv[1,0]", a_inv.get(1, 0), 1.5, 1e-10);
    assert_close("inv[1,1]", a_inv.get(1, 1), -0.5, 1e-10);
}

// ── Cholesky ──

#[test]
fn f02_cholesky_reconstruction() {
    // LL^T = A for SPD matrix (numpy.linalg.cholesky)
    let a = Mat::from_rows(&[
        &[4.0, 12.0, -16.0],
        &[12.0, 37.0, -43.0],
        &[-16.0, -43.0, 98.0],
    ]);
    let l = cholesky(&a).unwrap();
    let llt = mat_mul(&l, &l.t());
    mat_close("LL^T", &llt, &a, 1e-10);
    // L should be lower triangular
    for i in 0..3 {
        for j in i + 1..3 {
            assert_close(&format!("L[{},{}]", i, j), l.get(i, j), 0.0, 1e-14);
        }
    }
}

#[test]
fn f02_cholesky_solve_spd() {
    // Solve SPD system: [[4,2],[2,3]] x = [8,7]
    let a = Mat::from_rows(&[&[4.0, 2.0], &[2.0, 3.0]]);
    let b = vec![8.0, 7.0];
    let x = solve_spd(&a, &b).unwrap();
    let ax = mat_vec(&a, &x);
    assert_close("spd_res[0]", ax[0], b[0], 1e-10);
    assert_close("spd_res[1]", ax[1], b[1], 1e-10);
}

#[test]
fn f02_cholesky_rejects_non_pd() {
    // [[1,5],[5,1]] has eigenvalues 6 and -4 → not PD
    let a = Mat::from_rows(&[&[1.0, 5.0], &[5.0, 1.0]]);
    assert!(cholesky(&a).is_none(), "should reject non-PD matrix");
}

