// ── erf/erfc ──

#[test]
fn f00_erf_known_values() {
    // scipy.special.erf
    assert_close("erf(0)", erf(0.0), 0.0, 1e-8); // A&S 7.1.26 max error 1.5e-7
    assert_close("erf(1)", erf(1.0), 0.8427007929497149, 1e-6);
    assert_close("erf(2)", erf(2.0), 0.9953222650189527, 1e-6);
    assert_close("erf(-1)", erf(-1.0), -0.8427007929497149, 1e-6);
}

#[test]
fn f00_erf_erfc_complement() {
    // erf(x) + erfc(x) = 1 for all x
    for &x in &[0.0, 0.5, 1.0, 2.0, 3.0, -1.5] {
        assert_close(&format!("erf+erfc({})", x), erf(x) + erfc(x), 1.0, 1e-10);
    }
}

#[test]
fn f00_erf_odd_symmetry() {
    // erf(-x) = -erf(x)
    for &x in &[0.5, 1.0, 2.5] {
        assert_close(&format!("erf_sym({})", x), erf(-x), -erf(x), 1e-12);
    }
}

// ── gamma/log_gamma ──

#[test]
fn f00_gamma_factorials() {
    // Γ(n) = (n-1)! for positive integers
    // scipy.special.gamma
    assert_close("Γ(1)", gamma(1.0), 1.0, 1e-10);      // 0! = 1
    assert_close("Γ(2)", gamma(2.0), 1.0, 1e-10);      // 1! = 1
    assert_close("Γ(5)", gamma(5.0), 24.0, 1e-8);      // 4! = 24
    assert_close("Γ(7)", gamma(7.0), 720.0, 1e-6);     // 6! = 720
    assert_close("Γ(0.5)", gamma(0.5), std::f64::consts::PI.sqrt(), 1e-8); // √π
}

#[test]
fn f00_log_gamma_large() {
    // Stirling-scale: ln(Γ(100)) = ln(99!) ≈ 359.13
    // scipy: lgamma(100) = 359.1342053695754
    assert_close("lnΓ(100)", log_gamma(100.0), 359.1342053695754, 1e-6);
}

#[test]
fn f00_log_beta_known() {
    // B(a,b) = Γ(a)Γ(b)/Γ(a+b)
    // B(2,3) = 1!·2!/4! = 1·2/24 = 1/12 → ln(1/12) ≈ -2.485
    let expected = (1.0_f64 / 12.0).ln();
    assert_close("lnB(2,3)", log_beta(2.0, 3.0), expected, 1e-8);
}

// ── incomplete beta ──

#[test]
fn f00_ibeta_uniform() {
    // I_x(1,1) = x (uniform CDF)
    for &x in &[0.0, 0.25, 0.5, 0.75, 1.0] {
        assert_close(&format!("I_{}(1,1)", x), regularized_incomplete_beta(x, 1.0, 1.0), x, 1e-10);
    }
}

#[test]
fn f00_ibeta_symmetry() {
    // I_x(a,b) + I_{1-x}(b,a) = 1
    let x = 0.3;
    let a = 2.5;
    let b = 3.7;
    let sum = regularized_incomplete_beta(x, a, b) + regularized_incomplete_beta(1.0 - x, b, a);
    assert_close("ibeta_sym", sum, 1.0, 1e-10);
}

// ── incomplete gamma ──

#[test]
fn f00_igamma_exponential_cdf() {
    // P(1,x) = 1 - exp(-x) (exponential CDF)
    for &x in &[0.5_f64, 1.0, 2.0, 5.0] {
        let expected = 1.0 - (-x).exp();
        assert_close(&format!("P(1,{})", x), regularized_gamma_p(1.0, x), expected, 1e-10);
    }
}

#[test]
fn f00_igamma_pq_complement() {
    // P(a,x) + Q(a,x) = 1
    for &(a, x) in &[(2.0, 3.0), (0.5, 1.0), (5.0, 2.0)] {
        let sum = regularized_gamma_p(a, x) + regularized_gamma_q(a, x);
        assert_close(&format!("P+Q({},{})", a, x), sum, 1.0, 1e-10);
    }
}

