#[test]
fn f04_shuffle_preserves_elements() {
    use tambear::rng::{Xoshiro256, shuffle};
    let mut rng = Xoshiro256::new(42);
    let mut data: Vec<i32> = (0..100).collect();
    let original: Vec<i32> = data.clone();
    shuffle(&mut rng, &mut data);
    // Same elements, just reordered
    let mut sorted = data.clone();
    sorted.sort();
    assert_eq!(sorted, original, "shuffle must preserve all elements");
    // Highly unlikely to be in original order
    assert_ne!(data, original, "shuffle should reorder elements");
}

#[test]
fn f04_sample_without_replacement_unique() {
    use tambear::rng::{Xoshiro256, sample_without_replacement};
    let mut rng = Xoshiro256::new(42);
    let indices = sample_without_replacement(&mut rng, 100, 20);
    assert_eq!(indices.len(), 20);
    // All unique
    let mut sorted = indices.clone();
    sorted.sort();
    sorted.dedup();
    assert_eq!(sorted.len(), 20, "sample_without_replacement must produce unique indices");
    // All in range
    for &idx in &indices {
        assert!(idx < 100, "index {} out of range", idx);
    }
}

#[test]
fn f04_fill_uniform_correctness() {
    use tambear::rng::{Xoshiro256, TamRng, fill_uniform};
    let mut rng = Xoshiro256::new(42);
    let mut buf = vec![0.0; 1000];
    fill_uniform(&mut rng, &mut buf);
    for &v in &buf {
        assert!(v >= 0.0 && v < 1.0, "fill_uniform value out of range: {}", v);
    }
    // Mean should be ~0.5
    let mean: f64 = buf.iter().sum::<f64>() / buf.len() as f64;
    assert_close("fill_uniform mean", mean, 0.5, 0.05);
}

