#[test]
fn f23_gelu_known_values() {
    // torch.nn.functional.gelu([-1, 0, 1]) using tanh approximation
    // gelu(0) = 0, gelu(1) ≈ 0.8412, gelu(-1) ≈ -0.1588
    use tambear::neural::gelu_vec;
    let result = gelu_vec(&[-1.0, 0.0, 1.0]);
    assert_close("gelu(0)", result[1], 0.0, 1e-14);
    // GELU is approximately symmetric: gelu(x) + gelu(-x) ≈ 0 only at 0
    // gelu(1) ≈ 0.8412 (PyTorch tanh approx)
    assert_close("gelu(1)", result[2], 0.8411919906082768, 1e-4);
    assert_close("gelu(-1)", result[0], -0.15880800939172324, 1e-4);
}

