#[test]
fn f23_selu_self_normalizing() {
    // SELU constants from Klambauer et al. 2017
    // selu(1.0) = lambda * 1.0 = 1.0507009873554805
    // selu(-1.0) = lambda * alpha * (exp(-1) - 1)
    use tambear::neural::{selu, SELU_ALPHA, SELU_LAMBDA};
    assert_close("selu(1)", selu(1.0), SELU_LAMBDA, 1e-14);
    assert_close("selu(0)", selu(0.0), 0.0, 1e-14);
    let expected_neg = SELU_LAMBDA * SELU_ALPHA * ((-1.0_f64).exp() - 1.0);
    assert_close("selu(-1)", selu(-1.0), expected_neg, 1e-14);
}

#[test]
fn f23_log_softmax_known_values() {
    // torch.nn.functional.log_softmax([1,2,3]) = log(softmax([1,2,3]))
    // = [1 - log(sum(exp)), 2 - log(sum(exp)), 3 - log(sum(exp))]
    use tambear::neural::log_softmax;
    let result = log_softmax(&[1.0, 2.0, 3.0]);
    let lse = (1.0_f64.exp() + 2.0_f64.exp() + 3.0_f64.exp()).ln();
    let expected = [1.0 - lse, 2.0 - lse, 3.0 - lse];
    assert_slices_close("log_softmax", &result, &expected, 1e-12);
    // Verify exp(log_softmax) sums to 1
    let sum: f64 = result.iter().map(|&v| v.exp()).sum();
    assert_close("exp(log_softmax) sum", sum, 1.0, 1e-12);
}

