#[test]
fn f23_layer_norm_known() {
    // 2 samples, 3 features. Input: [[1, 2, 3], [4, 4, 4]].
    // gamma=[1,1,1], beta=[0,0,0], eps=0.
    // Sample 0: mean=2, var=2/3. Normalized: [-1/√(2/3), 0, 1/√(2/3)] = [-√(3/2), 0, √(3/2)]
    // Sample 1: mean=4, var=0. With eps→0: division by ~0.
    // Use eps=1e-5 and only test sample 0.
    use tambear::neural::layer_norm;
    let input = vec![1.0, 2.0, 3.0, 10.0, 10.0, 10.0];
    let gamma = vec![1.0, 1.0, 1.0];
    let beta = vec![0.0, 0.0, 0.0];
    let result = layer_norm(&input, 2, 3, &gamma, &beta, 1e-5);
    let inv_std = (2.0_f64 / 3.0 + 1e-5).sqrt().recip();
    assert_close("layer_norm[0]", result[0], -1.0 * inv_std, 1e-10);
    assert_close("layer_norm[1]", result[1], 0.0, 1e-10);
    assert_close("layer_norm[2]", result[2], 1.0 * inv_std, 1e-10);
    // Sample 1: all identical → normalized to 0 (with gamma=1, beta=0)
    assert_close("layer_norm constant", result[3], 0.0, 1e-3);
}

