#[test]
fn f23_positional_encoding_orthogonality() {
    // Vaswani et al. 2017: positional encoding uses sin/cos with varying frequencies.
    // pos_enc[0, 0] = sin(0/10000^(0/d)) = sin(0) = 0
    // pos_enc[0, 1] = cos(0/10000^(0/d)) = cos(0) = 1
    use tambear::neural::positional_encoding;
    let pe = positional_encoding(10, 4);
    assert_eq!(pe.rows, 10);
    assert_eq!(pe.cols, 4);
    // Position 0, dim 0: sin(0) = 0
    assert_close("pe[0,0]", pe.data[0], 0.0, 1e-14);
    // Position 0, dim 1: cos(0) = 1
    assert_close("pe[0,1]", pe.data[1], 1.0, 1e-14);
}

