#[test]
fn f35_knn_from_distance_known() {
    // Hand-computed: 4 points in 2D: (0,0), (1,0), (3,0), (10,0)
    // L2Sq distances: d(0,1)=1, d(0,2)=9, d(0,3)=100, d(1,2)=4, d(1,3)=81, d(2,3)=49
    // k=2: point 0 → [1, 2]; point 1 → [0, 2]; point 2 → [1, 0]; point 3 → [2, 1]
    use tambear::knn::knn_from_distance;
    use tambear::intermediates::{DistanceMatrix, Metric};
    use std::sync::Arc;

    let dist_data = vec![
        0.0, 1.0, 9.0, 100.0,
        1.0, 0.0, 4.0, 81.0,
        9.0, 4.0, 0.0, 49.0,
        100.0, 81.0, 49.0, 0.0,
    ];
    let dist = DistanceMatrix { metric: Metric::L2Sq, n: 4, data: Arc::new(dist_data) };
    let result = knn_from_distance(&dist, 2);

    assert_eq!(result.n, 4);
    assert_eq!(result.k, 2);

    // sklearn: NearestNeighbors(n_neighbors=2, metric='precomputed').fit(D)
    // Point 0: nearest = [1, 2] with distances [1, 9]
    let n0 = result.neighbor_indices(0);
    assert_eq!(n0[0], 1, "point 0 nearest should be point 1");
    assert_eq!(n0[1], 2, "point 0 second nearest should be point 2");

    // Point 3: nearest = [2, 1] with distances [49, 81]
    let n3 = result.neighbor_indices(3);
    assert_eq!(n3[0], 2, "point 3 nearest should be point 2");
    assert_eq!(n3[1], 1, "point 3 second nearest should be point 1");
}

