#[test]
fn f35_knn_session_reuses_distance() {
    // The session should reuse the distance matrix from DBSCAN
    use tambear::intermediates::TamSession;
    use tambear::clustering::ClusteringEngine;
    use tambear::knn::knn_session;

    let data = vec![0.0, 0.0,  1.0, 0.0,  5.0, 5.0,  5.5, 5.0];
    let mut session = TamSession::new();
    let mut engine = ClusteringEngine::new().unwrap();

    // DBSCAN computes distance matrix, registers in session
    let _clusters = engine.dbscan_session(&mut session, &data, 4, 2, 2.0, 2).unwrap();
    let session_len_after_dbscan = session.len();

    // KNN should find the distance matrix in session — zero additional GPU cost
    let knn = knn_session(&mut session, &data, 4, 2, 2).unwrap();
    let session_len_after_knn = session.len();

    assert_eq!(knn.n, 4);
    assert_eq!(knn.k, 2);
    // Session should NOT have grown (distance matrix was reused)
    assert_eq!(session_len_after_knn, session_len_after_dbscan,
        "KNN should reuse DBSCAN's distance matrix, not compute a new one");
}

// ===========================================================================
// CANCELLATION CANARY TESTS — Prove naive E[x²]-E[x]² bugs, verify fixes
// ===========================================================================
//
// These tests assert CORRECT behavior at escalating offsets (1e4 → 1e12).
// The naive formula `sum_sq/n - mean²` loses all precision at high offsets
// because both terms are O(offset²) while the variance is O(spread²).
//
// STATUS: SufficientStatistics::variance() and GroupByResult::variances() are
//         now DEPRECATED — they use naive sum_sq/n - mean² which fails at high
//         offsets. The correct path is MomentStats (centered two-pass).
//
// These canary tests prove MomentStats survives all offsets (1e4 → 1e12).
//
// Deprecated (naive, documented as broken):
//   1. hash_scatter.rs — GroupByResult::variances()
//   2. intermediates.rs — SufficientStatistics::variance()
//
// Already fixed (no canary needed):
//   4. robust.rs:ols_subset — now centered ✓
//   5. complexity.rs:linear_fit_segment — now centered ✓
//   6-7. complexity.rs and robust.rs OLS slopes — now centered ✓

/// Helper: generate data with known variance at a given offset.
/// Returns (values, true_variance_population).
/// Data: 100 points of offset + i*0.001 for i in 0..100.
/// True variance (population) = Var(0, 0.001, ..., 0.099)
///   = (n²-1) * step² / 12 = (10000-1) * 1e-6 / 12 ≈ 8.3325e-4
fn canary_data(offset: f64) -> (Vec<f64>, f64) {
    let n = 100;
    let step = 0.001;
    let data: Vec<f64> = (0..n).map(|i| offset + i as f64 * step).collect();
    let expected_var = (n as f64 * n as f64 - 1.0) * step * step / 12.0;
    (data, expected_var)
}

// ---------------------------------------------------------------------------
// Canary 1: MomentStats variance survives all offsets (centered two-pass)
// Proves the CORRECT path works where the naive formula fails.
// ---------------------------------------------------------------------------

#[test]
fn canary_moments_variance_offset_1e4() {
    canary_moments_at_offset(1e4, "1e4");
}

#[test]
fn canary_moments_variance_offset_1e6() {
    canary_moments_at_offset(1e6, "1e6");
}

#[test]
fn canary_moments_variance_offset_1e8() {
    canary_moments_at_offset(1e8, "1e8");
}

#[test]
fn canary_moments_variance_offset_1e10() {
    canary_moments_at_offset(1e10, "1e10");
}

#[test]
fn canary_moments_variance_offset_1e12() {
    canary_moments_at_offset(1e12, "1e12");
}

fn canary_moments_at_offset(offset: f64, label: &str) {
    let (data, expected_var) = canary_data(offset);

    let stats = moments_ungrouped(&data);
    let got = stats.variance(0); // population variance

    let rel_err = if expected_var > 0.0 { ((got - expected_var) / expected_var).abs() } else { got.abs() };
    assert!(rel_err < 0.01,
        "MomentStats::variance at offset={}: got={:.6e}, expected={:.6e}, rel_err={:.2e}",
        label, got, expected_var, rel_err);
}

