fn canary_moments_std_at_offset(offset: f64, label: &str) {
    let (data, expected_var) = canary_data(offset);
    let expected_std = expected_var.sqrt();

    let stats = moments_ungrouped(&data);
    let got = stats.std(0);

    let rel_err = ((got - expected_std) / expected_std).abs();
    assert!(rel_err < 0.01,
        "MomentStats::std at offset={}: got={:.6e}, expected={:.6e}, rel_err={:.2e}",
        label, got, expected_std, rel_err);
}

// ---------------------------------------------------------------------------
// Canary 3: multi-offset — different offsets, same variance
// ---------------------------------------------------------------------------

#[test]
fn canary_moments_multi_offset_stability() {
    // Prove MomentStats produces identical variance regardless of offset
    let offsets = [0.0, 1e4, 1e8, 1e10, 1e12];
    let mut variances = Vec::new();

    for &offset in &offsets {
        let (data, _) = canary_data(offset);
        let stats = moments_ungrouped(&data);
        variances.push(stats.variance(0));
    }

    // All should be within 1% of each other (the true variance is ~8.3325e-4)
    let v0 = variances[0];
    for (i, &v) in variances.iter().enumerate() {
        let rel_err = ((v - v0) / v0).abs();
        assert!(rel_err < 0.01,
            "Offset {:.0e}: variance={:.6e} differs from offset-0 variance={:.6e} by {:.2e}",
            offsets[i], v, v0, rel_err);
    }
}

// ===========================================================================
// CROSS-ALGORITHM SHARING — Paper 3 evidence: zero-GPU-cost DBSCAN→KNN
// ===========================================================================
//
// These tests prove the headline claim of Paper 3: "Cross-algorithm sharing
// reduces GPU computation by reusing intermediate results via TamSession."
//
// The key result: DBSCAN computes an O(n²d) GPU distance matrix. KNN retrieves
// it from the session at zero additional GPU cost, performing only O(n²k) CPU
// work. Multiple consumers can share the same intermediate.

#[test]
fn sharing_dbscan_to_knn_zero_gpu_reuse() {
    // EVIDENCE: DBSCAN→KNN distance matrix sharing.
    // This is the definitive test for Paper 3's headline claim.
    use tambear::intermediates::TamSession;
    use tambear::clustering::ClusteringEngine;
    use tambear::knn::knn_session;

    // Two tight clusters: (0,0)-(1,0) and (5,5)-(5.5,5)
    let data = vec![0.0, 0.0,  1.0, 0.0,  5.0, 5.0,  5.5, 5.0];
    let n = 4;
    let d = 2;

    let mut session = TamSession::new();
    assert_eq!(session.len(), 0, "session starts empty");

    // Step 1: DBSCAN computes distance matrix (GPU) and registers in session
    let mut engine = ClusteringEngine::new().unwrap();
    let clusters = engine.dbscan_session(&mut session, &data, n, d, 2.0, 2).unwrap();
    let session_after_dbscan = session.len();
    assert!(session_after_dbscan > 0, "DBSCAN must register distance matrix in session");

    // Verify DBSCAN correctness: 2 clusters, no noise
    assert_eq!(clusters.n_clusters, 2, "expected 2 clusters");
    assert_eq!(clusters.labels[0], clusters.labels[1], "points 0,1 in same cluster");
    assert_eq!(clusters.labels[2], clusters.labels[3], "points 2,3 in same cluster");
    assert_ne!(clusters.labels[0], clusters.labels[2], "clusters should differ");

    // Step 2: KNN retrieves distance matrix from session (ZERO GPU cost)
    let knn_k2 = knn_session(&mut session, &data, n, d, 2).unwrap();
    let session_after_knn1 = session.len();

    // PROOF: session did not grow — distance matrix was REUSED, not recomputed
    assert_eq!(session_after_knn1, session_after_dbscan,
        "SHARING PROOF: KNN must reuse DBSCAN's distance matrix (session grew from {} to {})",
        session_after_dbscan, session_after_knn1);

    // Verify KNN correctness with shared matrix
    // Point 0 (0,0): nearest is point 1 (1,0) at d²=1, then point 2 (5,5) at d²=50
    let n0 = knn_k2.neighbor_indices(0);
    assert_eq!(n0[0], 1, "point 0's nearest neighbor should be point 1");

    // Point 2 (5,5): nearest is point 3 (5.5,5) at d²=0.25, then point 1 (1,0) at d²=41
    let n2 = knn_k2.neighbor_indices(2);
    assert_eq!(n2[0], 3, "point 2's nearest neighbor should be point 3");

    // Step 3: Second KNN with different k — STILL no GPU (same distance matrix)
    let knn_k1 = knn_session(&mut session, &data, n, d, 1).unwrap();
    let session_after_knn2 = session.len();

    assert_eq!(session_after_knn2, session_after_dbscan,
        "SHARING PROOF: second KNN(k=1) still reuses same distance matrix");

    // Different k, same nearest neighbor
    assert_eq!(knn_k1.neighbor_indices(0)[0], 1, "k=1 should find same nearest");
    assert_eq!(knn_k1.neighbor_indices(2)[0], 3, "k=1 should find same nearest");
}

#[test]
fn sharing_multiple_consumers_same_session() {
    // EVIDENCE: Three algorithms sharing one distance matrix.
    // DBSCAN → KNN(k=1) → KNN(k=3): all use the same GPU-computed O(n²d) matrix.
    use tambear::intermediates::TamSession;
    use tambear::clustering::ClusteringEngine;
    use tambear::knn::knn_session;

    let data = vec![
        0.0, 0.0,  0.5, 0.0,  1.0, 0.0,   // line segment
        10.0, 10.0,  10.5, 10.0,  11.0, 10.0,  // another line
    ];
    let n = 6;
    let d = 2;

    let mut session = TamSession::new();
    let mut engine = ClusteringEngine::new().unwrap();

    // Consumer 1: DBSCAN (computes distance matrix on GPU)
    let clusters = engine.dbscan_session(&mut session, &data, n, d, 2.0, 2).unwrap();
    let baseline = session.len();

    // Consumer 2: KNN k=2
    let knn2 = knn_session(&mut session, &data, n, d, 2).unwrap();
    assert_eq!(session.len(), baseline, "KNN(k=2) reuses distance matrix");

    // Consumer 3: KNN k=4
    let knn4 = knn_session(&mut session, &data, n, d, 4).unwrap();
    assert_eq!(session.len(), baseline, "KNN(k=4) reuses distance matrix");

    // All three consumers agree on structure:
    // DBSCAN: 2 clusters of 3 points each
    assert_eq!(clusters.n_clusters, 2);

    // KNN(k=2): point 0's neighbors are within its cluster (points 1, 2)
    let n0 = knn2.neighbor_indices(0);
    assert!(n0.contains(&1) && n0.contains(&2),
        "KNN(k=2) point 0 should see points 1,2 as neighbors, got {:?}", n0);

    // KNN(k=4): point 0 sees all within-cluster + starts seeing cross-cluster
    assert_eq!(knn4.neighbor_indices(0).len(), 4);
}

