fn beale(x: &[f64]) -> f64 {
    (1.5 - x[0] + x[0]*x[1]).powi(2)
    + (2.25 - x[0] + x[0]*x[1].powi(2)).powi(2)
    + (2.625 - x[0] + x[0]*x[1].powi(3)).powi(2)
}

fn booth(x: &[f64]) -> f64 {
    (x[0] + 2.0*x[1] - 7.0).powi(2) + (2.0*x[0] + x[1] - 5.0).powi(2)
}

fn booth_grad(x: &[f64]) -> Vec<f64> {
    vec![
        2.0*(x[0]+2.0*x[1]-7.0) + 4.0*(2.0*x[0]+x[1]-5.0),
        4.0*(x[0]+2.0*x[1]-7.0) + 2.0*(2.0*x[0]+x[1]-5.0),
    ]
}

#[test]
fn f05_oracle_beale_nelder_mead() {
    // scipy: true min at (3.0, 0.5), f=0 — tol=0.01
    let r = nelder_mead(&beale, &[0.0, 0.0], 1.0, 50000, 1e-12);
    assert_close("beale_x0", r.x[0], 3.0, 0.01);
    assert_close("beale_x1", r.x[1], 0.5, 0.01);
    assert!(r.f_val < 1e-4, "beale f*={}", r.f_val);
}

#[test]
fn f05_oracle_booth_lbfgsb() {
    // scipy: true min at (1.0, 3.0), f=0 — tol=1e-6
    let r = lbfgs(&booth, &booth_grad, &[0.0, 0.0], 10, 1000, 1e-10);
    assert_close("booth_x0", r.x[0], 1.0, 1e-4);
    assert_close("booth_x1", r.x[1], 3.0, 1e-4);
    assert!(r.f_val < 1e-6, "booth f*={}", r.f_val);
}

