// ═══════════════════════════════════════════════════════════════════════
// SVD ADVERSARIAL VALIDATION — Task #22
// ═══════════════════════════════════════════════════════════════════════
//
// Tests that prove the one-sided Jacobi SVD (linear_algebra.rs) handles
// ill-conditioned matrices correctly. The old A^T A approach squared κ,
// causing 41% error. These adversarial tests verify machine-epsilon accuracy.

/// Reconstruct A from SVD: A ≈ U * diag(sigma) * Vt
fn reconstruct_from_svd(u: &Mat, sigma: &[f64], vt: &Mat) -> Mat {
    let m = u.rows;
    let n = vt.cols;
    let k = sigma.len();
    let mut result = Mat::zeros(m, n);
    for i in 0..m {
        for j in 0..n {
            let mut s = 0.0;
            for l in 0..k {
                s += u.get(i, l) * sigma[l] * vt.get(l, j);
            }
            result.set(i, j, s);
        }
    }
    result
}

fn mat_max_diff(a: &Mat, b: &Mat) -> f64 {
    assert_eq!(a.rows, b.rows);
    assert_eq!(a.cols, b.cols);
    let mut max = 0.0f64;
    for i in 0..a.rows {
        for j in 0..a.cols {
            max = max.max((a.get(i, j) - b.get(i, j)).abs());
        }
    }
    max
}

#[test]
fn svd_adversarial_diagonal_wellconditioned() {
    // Diagonal matrix σ=[3, 2, 1] — trivial case, should be exact.
    let a = Mat::from_vec(3, 3, vec![
        3.0, 0.0, 0.0,
        0.0, 2.0, 0.0,
        0.0, 0.0, 1.0,
    ]);
    let r = svd(&a);

    assert_close("svd_diag_s0", r.sigma[0], 3.0, 1e-14);
    assert_close("svd_diag_s1", r.sigma[1], 2.0, 1e-14);
    assert_close("svd_diag_s2", r.sigma[2], 1.0, 1e-14);

    let recon = reconstruct_from_svd(&r.u, &r.sigma, &r.vt);
    let err = mat_max_diff(&a, &recon);
    assert!(err < 1e-14, "svd_diag reconstruction error: {:.2e}", err);
}

#[test]
fn svd_adversarial_diagonal_illconditioned() {
    // THE KEY ADVERSARIAL TEST: σ=[1, 1e-8]
    // κ = 1e8. The old A^T A approach squares this to κ²=1e16,
    // destroying all precision. The one-sided Jacobi should be exact.
    let a = Mat::from_vec(2, 2, vec![
        1.0, 0.0,
        0.0, 1e-8,
    ]);
    let r = svd(&a);

    assert_close("svd_illcond_s0", r.sigma[0], 1.0, 1e-14);
    assert_close("svd_illcond_s1", r.sigma[1], 1e-8, 1e-22);

    let recon = reconstruct_from_svd(&r.u, &r.sigma, &r.vt);
    let err = mat_max_diff(&a, &recon);
    assert!(err < 1e-14, "svd_illcond reconstruction error: {:.2e}", err);
}

