    // ── Mardia normality: skewed data → significant skewness ──────────

    #[test]
    fn mardia_skewed_data() {
        // Exponentially distributed data → should detect non-normality
        let n = 100;
        let p = 2;
        let mut data = Vec::with_capacity(n * p);
        let mut rng = 12345u64;
        for _ in 0..n {
            for _ in 0..p {
                // Simple LCG → map to exponential via -ln(U)
                rng = rng.wrapping_mul(6364136223846793005).wrapping_add(1);
                let u = (rng as f64 / u64::MAX as f64).max(1e-15);
                data.push(-u.ln()); // exponential(1) — heavily right-skewed
            }
        }
        let x = Mat::from_vec(n, p, data);
        let res = mardia_normality(&x);

        // Exponential data is heavily skewed → skewness test should reject
        assert!(res.skewness_p < 0.05,
            "Skewness p should be < 0.05 for exponential data, got {}", res.skewness_p);
    }

