        for w in rrs.windows(2) {
            assert!(e_value(w[1]) > e_value(w[0]),
                "E-value should be monotone: E({}) > E({})", w[1], w[0]);
        }
        // E-value(1) = 1 (no confounding needed for null effect)
        assert_close("e_val_null", e_value(1.0), 1.0, 1e-10);
