        let running: Vec<f64> = (-20..=20).map(|i| i as f64 * 0.5).collect();
        let outcome: Vec<f64> = running.iter().map(|&x| {
            x + if x >= 0.0 { 3.0 } else { 0.0 }
        }).collect();
