mod f09_robust {
    use super::*;
    use tambear::robust::{
        huber_weight, bisquare_weight,
        huber_m_estimate, medcouple,
    };
    use tambear::descriptive::{moments_ungrouped, sorted_nan_free, mad};

    // ─── Weight functions (mathematical definitions) ─────────────────

    #[test]
    fn huber_weight_values() {
        // huber(u, k): 1 if |u|<=k, else k/|u|
        let k = 1.345;
        assert_close("hw(0)", huber_weight(0.0, k), 1.0, 1e-12);
        assert_close("hw(0.5)", huber_weight(0.5, k), 1.0, 1e-12);
        assert_close("hw(1)", huber_weight(1.0, k), 1.0, 1e-12);
        assert_close("hw(1.345)", huber_weight(1.345, k), 1.0, 1e-12);
        assert_close("hw(2)", huber_weight(2.0, k), 0.6725, 1e-4);
        assert_close("hw(5)", huber_weight(5.0, k), 0.269, 1e-4);
    }

    #[test]
    fn bisquare_weight_values() {
        // bisquare(u, k): (1-(u/k)^2)^2 if |u|<=k, else 0
        let k = 4.685;
        assert_close("bw(0)", bisquare_weight(0.0, k), 1.0, 1e-12);
        assert_close("bw(1)", bisquare_weight(1.0, k), 0.9109562955029199, 1e-6);
        assert_close("bw(2)", bisquare_weight(2.0, k), 0.6687334118886328, 1e-6);
        assert_close("bw(4)", bisquare_weight(4.0, k), 0.07346532558577344, 1e-6);
        assert_close("bw(4.685)", bisquare_weight(4.685, k), 0.0, 1e-12);
        assert_close("bw(5)", bisquare_weight(5.0, k), 0.0, 1e-12);
    }

    // ─── Huber M-estimator of location ───────────────────────────────

    #[test]
    fn huber_m_location_contaminated() {
        // Normal(5,1) + 3 extreme outliers
        // Huber should be robust: location ≈ 5.12 despite outliers
        let mut data: Vec<f64> = vec![
            5.609434159508862, 2.920031787519009, 6.5009023916129145,
            6.881129432782428, 1.0979296226923272, 2.395640986275364,
            5.255680806334571, 4.367514815312836, 4.966397684991422,
            3.2939121448528397, 6.758795949725657, 6.555583870857896,
            5.132061395122432, 7.254482413936065, 5.935018684504091,
            3.2814150742335233, 5.737501568164998, 3.082234798342002,
            6.756900602614545, 4.900148178027494, 4.630275272909479,
            3.6381409111921172, 7.4450826773480605, 4.690941035862395,
            4.1433443556737855, 4.295732899023541, 6.064618371106698,
            5.730888128728156, 5.825465223191976, 5.8616420060157655,
            9.283295201740923, 4.187169967230769, 3.975514541856925,
            3.3724545435042446, 6.2319588451509915, 7.257944585441783,
            4.77210508469025, 3.319687046074944, 3.351037568617521,
            6.301185575649402, 6.486508342406885, 6.08630853661039,
            3.668980585422611, 5.464322646133439, 5.233371618281456,
            5.437377193458026, 6.7428575558963795, 5.447191097549364,
            6.35782712614379, 5.135158138977783,
        ];
        data.extend_from_slice(&[50.0, -30.0, 100.0]);
        let result = huber_m_estimate(&data, 1.345, 50, 1e-8);
        // Oracle: location ≈ 5.12 (robust to outliers)
        assert_close("huber_loc", result.location, 5.120683375185736, 1e-1);
        assert!(result.converged, "Huber should converge");
    }

    // ─── MAD on contaminated data ────────────────────────────────────

    #[test]
    fn mad_robust_to_outliers() {
        let mut data: Vec<f64> = vec![
            5.609434159508862, 2.920031787519009, 6.5009023916129145,
            6.881129432782428, 1.0979296226923272, 2.395640986275364,
            5.255680806334571, 4.367514815312836, 4.966397684991422,
            3.2939121448528397, 6.758795949725657, 6.555583870857896,
            5.132061395122432, 7.254482413936065, 5.935018684504091,
            3.2814150742335233, 5.737501568164998, 3.082234798342002,
            6.756900602614545, 4.900148178027494, 4.630275272909479,
            3.6381409111921172, 7.4450826773480605, 4.690941035862395,
            4.1433443556737855, 4.295732899023541, 6.064618371106698,
            5.730888128728156, 5.825465223191976, 5.8616420060157655,
            9.283295201740923, 4.187169967230769, 3.975514541856925,
            3.3724545435042446, 6.2319588451509915, 7.257944585441783,
            4.77210508469025, 3.319687046074944, 3.351037568617521,
            6.301185575649402, 6.486508342406885, 6.08630853661039,
            3.668980585422611, 5.464322646133439, 5.233371618281456,
            5.437377193458026, 6.7428575558963795, 5.447191097549364,
            6.35782712614379, 5.135158138977783,
        ];
        data.extend_from_slice(&[50.0, -30.0, 100.0]);
        let sorted = sorted_nan_free(&data);
        // MAD barely affected by 3 outliers in 53 points
        // scipy confirms: median_abs_deviation(contaminated, scale=1) = 1.1182
        assert_close("mad_contaminated", mad(&sorted), 1.1182066773998702, 1e-6);
    }

    // ─── Medcouple (robust skewness) ─────────────────────────────────

    #[test]
    fn medcouple_symmetric_near_zero() {
        // For roughly symmetric data, medcouple should be near 0
        let data: Vec<f64> = (0..100).map(|i| {
            let x = (i as f64) * 0.1 - 5.0;
            x * x * 0.1 - 2.5 + (i as f64 * 7.3 % 3.1) - 1.55
        }).collect();
        let mc = medcouple(&data);
        assert!(
            mc.abs() < 0.5,
            "Medcouple of quasi-symmetric data should be near 0, got {:.4}", mc,
        );
    }
}

// ═══════════════════════════════════════════════════════════════════════════════
// F26: Complexity Analysis — Gold Standard Parity
//
// Oracle: research/gold_standard/family_26_complexity_oracle.py
// References: nolds (nonlinear dynamics library)
// ═══════════════════════════════════════════════════════════════════════════════

mod f26_complexity {
    use super::*;
    use tambear::complexity::{
        sample_entropy, permutation_entropy, hurst_rs, dfa,
    };

    // ─── Sample entropy ──────────────────────────────────────────────

    #[test]
    fn sampen_periodic_low() {
        // Periodic signal: SampEn should be low
        let data: Vec<f64> = (0..500).map(|i| (0.1 * i as f64).sin()).collect();
        let r = 0.2 * tambear::descriptive::moments_ungrouped(&data).std(1);
        let se = sample_entropy(&data, 2, r);
        assert!(se < 1.0, "Periodic SampEn should be < 1.0, got {:.4}", se);
    }

    #[test]
    fn sampen_random_higher_than_periodic() {
        // Random signal has higher SampEn than periodic
        let periodic: Vec<f64> = (0..500).map(|i| (0.1 * i as f64).sin()).collect();
        let r_p = 0.2 * tambear::descriptive::moments_ungrouped(&periodic).std(1);
        let se_p = sample_entropy(&periodic, 2, r_p);

        // Pseudo-random via deterministic hash
        let random: Vec<f64> = (0..500).map(|i| {
            let x = (i as f64 * 2.7182818 + 3.14159).sin() * 10000.0;
            x - x.floor()
        }).collect();
        let r_r = 0.2 * tambear::descriptive::moments_ungrouped(&random).std(1);
        let se_r = sample_entropy(&random, 2, r_r);
        assert!(se_r > se_p, "Random SampEn ({:.4}) should exceed periodic ({:.4})", se_r, se_p);
    }

    // ─── Permutation entropy ─────────────────────────────────────────

    #[test]
    fn pe_monotonic_is_zero() {
        // Monotonic data: only one ordinal pattern → PE = 0
        let data: Vec<f64> = (0..100).map(|i| i as f64).collect();
        let pe = permutation_entropy(&data, 3, 1);
        assert_close("PE_mono", pe, 0.0, 1e-12);
    }

    #[test]
    fn pe_max_is_ln_factorial() {
        // Max PE for m=3 is ln(3!) = ln(6) ≈ 1.7918
        // Max PE for m=4 is ln(4!) = ln(24) ≈ 3.1781
        let max_3 = (6.0f64).ln();
        let max_4 = (24.0f64).ln();
        assert_close("max_PE_3", max_3, 1.791759469228055, 1e-10);
        assert_close("max_PE_4", max_4, 3.1780538303479458, 1e-10);
    }

    // ─── Hurst exponent ──────────────────────────────────────────────

    #[test]
    fn hurst_trending_gt_half() {
        // Monotonically trending data should have H > 0.5
        let data: Vec<f64> = (0..2000).map(|i| {
            let t = i as f64 / 2000.0;
            t * 10.0 + (i as f64 * 0.137).sin() * 0.1
        }).collect();
        let h = hurst_rs(&data);
        assert!(h > 0.5, "Trending Hurst should be > 0.5, got {:.4}", h);
    }

    // ─── DFA ─────────────────────────────────────────────────────────

    #[test]
    fn dfa_white_noise_near_half() {
        // White noise: DFA α ≈ 0.5
        let data: Vec<f64> = (0..1000).map(|i| {
            let x = (i as f64 * 1.618033 + 2.71828).sin() * 10000.0;
            x - x.floor() - 0.5
        }).collect();
        let alpha = dfa(&data, 4, 64);
        assert!(
            alpha > 0.2 && alpha < 1.0,
            "White noise DFA α should be near 0.5, got {:.4}", alpha,
        );
    }

    #[test]
    fn dfa_brownian_near_1_5() {
        // Brownian motion (cumsum of white noise): DFA α ≈ 1.5
        let white: Vec<f64> = (0..1000).map(|i| {
            let x = (i as f64 * 1.618033 + 2.71828).sin() * 10000.0;
            x - x.floor() - 0.5
        }).collect();
        let brown: Vec<f64> = white.iter().scan(0.0, |s, x| { *s += x; Some(*s) }).collect();
        let alpha = dfa(&brown, 4, 64);
        assert!(
            alpha > 1.0 && alpha < 2.0,
            "Brownian DFA α should be near 1.5, got {:.4}", alpha,
        );
    }
}

