// F30: Spatial Statistics — Gold Standard Parity
//
// Oracle: research/gold_standard/family_30_spatial_oracle.py
// References: analytical formulas, scipy.spatial
// ═══════════════════════════════════════════════════════════════════════════════

mod f30_spatial {
    use super::*;
    use tambear::spatial::{
        euclidean_2d, haversine,
        spherical_variogram, exponential_variogram, gaussian_variogram,
        VariogramModel,
    };

    // ─── Euclidean distance ──────────────────────────────────────────

    #[test]
    fn euclidean_pythagorean() {
        assert_close("3-4-5", euclidean_2d(0.0, 0.0, 3.0, 4.0), 5.0, 1e-12);
    }

    #[test]
    fn euclidean_same_point() {
        assert_close("same", euclidean_2d(1.0, 2.0, 1.0, 2.0), 0.0, 1e-15);
    }

    #[test]
    fn euclidean_diagonal() {
        assert_close("diag", euclidean_2d(0.0, 0.0, 1.0, 1.0), 1.4142135623730951, 1e-12);
    }

    // ─── Haversine distance ──────────────────────────────────────────

    #[test]
    fn haversine_nyc_london() {
        let d = haversine(40.7128, -74.006, 51.5074, -0.1278);
        assert_close("NYC-LDN", d, 5570.222179737958, 10.0); // within 10 km
    }

    #[test]
    fn haversine_same_point() {
        assert_close("same", haversine(51.5074, -0.1278, 51.5074, -0.1278), 0.0, 1e-10);
    }

    #[test]
    fn haversine_equator_1deg() {
        let d = haversine(0.0, 0.0, 0.0, 1.0);
        assert_close("1deg", d, 111.19492664455873, 0.5); // within 0.5 km
    }

    // ─── Variogram models ────────────────────────────────────────────

    fn model(nugget: f64, sill: f64, range: f64) -> VariogramModel {
        VariogramModel { nugget, sill, range }
    }

    #[test]
    fn spherical_variogram_h5() {
        // γ(5) = 1.5*(5/10) - 0.5*(5/10)³ = 0.75 - 0.0625 = 0.6875
        let m = model(0.0, 1.0, 10.0);
        assert_close("sph_5", spherical_variogram(5.0, &m), 0.6875, 1e-12);
    }

    #[test]
    fn spherical_variogram_beyond_range() {
        // h > range → γ = sill
        let m = model(0.0, 1.0, 10.0);
        assert_close("sph_15", spherical_variogram(15.0, &m), 1.0, 1e-12);
    }

    #[test]
    fn exponential_variogram_h5() {
        // γ(5) = 1 - exp(-5/10) = 1 - exp(-0.5) ≈ 0.3935
        let m = model(0.0, 1.0, 10.0);
        assert_close("exp_5", exponential_variogram(5.0, &m), 0.7768698398515702, 1e-6);
    }

    #[test]
    fn gaussian_variogram_h5() {
        // γ(5) = 1 - exp(-(5/10)²) = 1 - exp(-0.25) ≈ 0.2212
        let m = model(0.0, 1.0, 10.0);
        assert_close("gauss_5", gaussian_variogram(5.0, &m), 0.5276334472589853, 1e-6);
    }

    #[test]
    fn spherical_with_nugget() {
        // nugget=0.5, sill=1.0: γ(5) = 0.5 + 0.5*[1.5*(0.5) - 0.5*(0.125)] = 0.5 + 0.6875*0.5
        let m = model(0.5, 1.0, 10.0);
        assert_close("sph_nug", spherical_variogram(5.0, &m), 1.1875, 1e-6);
    }
}
